// middleware/apiKeyAuth.js
const validateApiKey = (req, res, next) => {
  // Get API key from header
  const apiKey = req.headers['x-api-key'];

  // Check if API key exists
  if (!apiKey) {
    return res.status(401).json({
      success: false,
      error: {
        message: 'API key is required',
        hint: 'Include X-API-Key header in your request'
      }
    });
  }

  // Valid API keys (in real app, check database or env)
  const validApiKeys = [
    process.env.API_KEY_1,
    process.env.API_KEY_2
  ];

  // Validate the key
  if (!validApiKeys.includes(apiKey)) {
    return res.status(401).json({
      success: false,
      error: {
        message: 'Invalid API key'
      }
    });
  }

  // API key is valid — attach info to request and proceed
  req.apiKeyValid = true;
  req.apiKeyId = apiKey.substring(0, 8); // For logging

  next();
};

module.exports = validateApiKey;
```

**Usage:**

```javascript
const validateApiKey = require('./middleware/apiKeyAuth');

// Apply to all API routes
app.use('/api', validateApiKey);

// Or apply to specific routes
app.get('/api/data', validateApiKey, (req, res) => {
  res.json({ data: 'protected content' });
});
```

