**Regular Middleware** has 3 parameters: `(req, res, next)`
- Processes requests before they reach route handlers
- Can modify req/res, perform checks, log data
- Calls `next()` to continue or sends a response

**Error-Handling Middleware** has 4 parameters: `(err, req, res, next)`
- The first parameter `err` receives the error object
- Only runs when an error is passed via `next(error)`
- Used to centralize error handling logic

**Why 4 parameters?**

Express identifies error handlers **by their function signature**. It checks the number of parameters:

```javascript
// Express internally does something like:
if (middleware.length === 4) {
  // This is an error handler
} else {
  // This is regular middleware
}
```

**If you use only 3 parameters, Express won't recognize it as an error handler:**

```javascript
// ❌ WRONG — Won't catch errors (only 3 params)
app.use((err, req, res) => {
  res.status(500).json({ error: err.message });
});

// ✅ CORRECT — Catches errors (4 params)
app.use((err, req, res, next) => {
  res.status(500).json({ error: err.message });
});
```

**Error flow:**

```javascript
// Route throws error
app.get('/api/data', (req, res, next) => {
  try {
    throw new Error('Something failed');
  } catch (error) {
    next(error); // Pass to error handler
  }
});

// Error handler catches it
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({ error: err.message });
});
```

**Key points:**
- Error handlers must be defined **after** all routes
- Even if you don't use `next`, include it in the signature
- Multiple error handlers can be chained

```javascript
// routes/productRoutes.js
const express = require('express');
const router = express.Router();

// Simulated database
let products = [
  { id: 1, name: 'Laptop', price: 999, category: 'electronics' },
  { id: 2, name: 'Shirt', price: 29, category: 'clothing' }
];
let nextId = 3;

// Validation middleware
const validateProduct = (req, res, next) => {
  const { name, price, category } = req.body;
  const errors = [];

  if (!name || name.trim() === '') {
    errors.push('Name is required');
  }

  if (price === undefined || price === null) {
    errors.push('Price is required');
  } else if (typeof price !== 'number' || price < 0) {
    errors.push('Price must be a positive number');
  }

  if (!category || category.trim() === '') {
    errors.push('Category is required');
  }

  if (errors.length > 0) {
    return res.status(400).json({
      success: false,
      errors
    });
  }

  next();
};

// Validate ID parameter
const validateId = (req, res, next) => {
  const id = parseInt(req.params.id);

  if (isNaN(id) || id <= 0) {
    return res.status(400).json({
      success: false,
      error: 'Invalid product ID'
    });
  }

  req.productId = id;
  next();
};

// GET all products with filtering
router.get('/', (req, res) => {
  let result = [...products];

  // Filter by category
  if (req.query.category) {
    result = result.filter(p => 
      p.category.toLowerCase() === req.query.category.toLowerCase()
    );
  }

  // Filter by min price
  if (req.query.minPrice) {
    result = result.filter(p => p.price >= parseFloat(req.query.minPrice));
  }

  // Sort
  if (req.query.sort === 'price') {
    result.sort((a, b) => a.price - b.price);
  }

  res.status(200).json({
    success: true,
    count: result.length,
    data: result
  });
});

// GET single product
router.get('/:id', validateId, (req, res) => {
  const product = products.find(p => p.id === req.productId);

  if (!product) {
    return res.status(404).json({
      success: false,
      error: 'Product not found'
    });
  }

  res.status(200).json({
    success: true,
    data: product
  });
});

// POST create product
router.post('/', validateProduct, (req, res) => {
  const { name, price, category } = req.body;

  const newProduct = {
    id: nextId++,
    name: name.trim(),
    price,
    category: category.trim().toLowerCase(),
    createdAt: new Date()
  };

  products.push(newProduct);

  res.status(201).json({
    success: true,
    data: newProduct
  });
});

// PUT update product
router.put('/:id', validateId, validateProduct, (req, res) => {
  const index = products.findIndex(p => p.id === req.productId);

  if (index === -1) {
    return res.status(404).json({
      success: false,
      error: 'Product not found'
    });
  }

  const { name, price, category } = req.body;

  products[index] = {
    ...products[index],
    name: name.trim(),
    price,
    category: category.trim().toLowerCase(),
    updatedAt: new Date()
  };

  res.status(200).json({
    success: true,
    data: products[index]
  });
});

// DELETE product
router.delete('/:id', validateId, (req, res) => {
  const index = products.findIndex(p => p.id === req.productId);

  if (index === -1) {
    return res.status(404).json({
      success: false,
      error: 'Product not found'
    });
  }

  products.splice(index, 1);

  res.status(204).send();
});

module.exports = router;
```

**Usage in app.js:**
```javascript
const productRoutes = require('./routes/productRoutes');
app.use('/api/v1/products', productRoutes);
```

**HTTP Status Codes Used:**
- `200` — Success (GET, PUT)
- `201` — Created (POST)
- `204` — No Content (DELETE)
- `400` — Bad Request (validation errors)
- `404` — Not Found
